def hsv_from_rgb(rgb):
    r, g, b = [float(x) for x in rgb]
    h, s, v = colorsys.rgb_to_hsv(r, g, b)
    return {
        'hue_angle': float(h * 360.0),
        'saturation': float(s),
        'brightness': float(v),
        'hsv': [float(h), float(s), float(v)]
    }

def rgb_to_hex(rgb):
    r, g, b = [int(np.clip(x, 0.0, 1.0) * 255) for x in rgb]
    return f'#{r:02x}{g:02x}{b:02x}'
